System.register([],function(e,t){return{setters:[],execute:function(){e("t",{moduleId:"economist-sentence-logic-diagnostic",version:"v1",title:"句意逻辑与句子分析测试"}),e("r",[{id:"logic-relations",title:"句意逻辑",description:"聚焦句内意群之间的逻辑推进、关系判断与作者论证路径。"},{id:"sentence-analysis",title:"句子分析",description:"聚焦主干提取、从句功能、非谓语压缩和修饰语指向。"}]),e("n",[{id:"logic-cause-1",sectionId:"logic-relations",categoryKey:"cause-effect",categoryLabel:"因果",prompt:"句中两个意群最核心的逻辑关系是什么？",sourceSentence:"With borrowing costs now at a decade high, households are cutting discretionary spending more aggressively than retailers expected.",options:[{key:"A",label:"前半句提供原因，后半句给出结果。"},{key:"B",label:"前半句只是让步背景，后半句才是真正观点。"},{key:"C",label:"前后两部分构成并列补充，没有主次之分。"},{key:"D",label:"后半句解释前半句中的名词短语。"}],correctOptionKey:"A",explanation:"With 引出的介词结构说明高借贷成本这一原因，主句说明家庭削减可支配消费这一结果。"},{id:"logic-cause-2",sectionId:"logic-relations",categoryKey:"cause-effect",categoryLabel:"因果",prompt:"作者如何组织这句话的推理链？",sourceSentence:"Because regulators moved late, the rescue became costlier than it needed to be.",options:[{key:"A",label:"先交代结果，再追溯原因。"},{key:"B",label:"先交代原因，再指出后果。"},{key:"C",label:"先提出假设，再修正判断。"},{key:"D",label:"先举例说明，再概括结论。"}],correctOptionKey:"B",explanation:"Because 从句明确先给出监管行动迟缓的原因，主句随后给出救助成本更高的结果。"},{id:"logic-cause-3",sectionId:"logic-relations",categoryKey:"cause-effect",categoryLabel:"因果",prompt:"哪一项最准确概括句子的逻辑方向？",sourceSentence:"The currency slid after investors concluded that higher rates would not be enough to restore confidence.",options:[{key:"A",label:"先判断市场结果，再补充投资者的心理原因。"},{key:"B",label:"先陈述投资者信念，再说明货币下跌。"},{key:"C",label:"句子主要比较两种政策后果。"},{key:"D",label:"句子强调条件成立时的未来可能性。"}],correctOptionKey:"A",explanation:"主句先给出货币下跌这一结果，after 引导的从句补充其原因背景。"},{id:"logic-contrast-1",sectionId:"logic-relations",categoryKey:"contrast-concession",categoryLabel:"转折让步",prompt:"句中 although 从句与主句形成的关系是？",sourceSentence:"Although inflation has eased, households still feel poorer because wages have not fully caught up.",options:[{key:"A",label:"前半句反驳后半句。"},{key:"B",label:"前半句构成让步，后半句给出主结论。"},{key:"C",label:"前半句只是举例，后半句概括规律。"},{key:"D",label:"前后两句构成因果并列。"}],correctOptionKey:"B",explanation:"Although 引出让步背景，作者真正要强调的是 households 仍然感到更穷。"},{id:"logic-contrast-2",sectionId:"logic-relations",categoryKey:"contrast-concession",categoryLabel:"转折让步",prompt:"Yet 在句中最主要的作用是什么？",sourceSentence:"The technology is promising, yet scaling it commercially remains painfully difficult.",options:[{key:"A",label:"递进补充前一句的积极评价。"},{key:"B",label:"转出与前一句预期不一致的限制。"},{key:"C",label:"表示条件成立后的结果。"},{key:"D",label:"解释 technology 的具体内容。"}],correctOptionKey:"B",explanation:"Yet 将 promising 的积极预期转向商业扩张仍然困难的现实限制。"},{id:"logic-contrast-3",sectionId:"logic-relations",categoryKey:"contrast-concession",categoryLabel:"转折让步",prompt:"哪项最贴近 however 所体现的作者态度？",sourceSentence:"Exports have recovered; however, the rebound is too narrow to guarantee a durable recovery.",options:[{key:"A",label:"先承认积极信号，再提出保留。"},{key:"B",label:"先提出担忧，再给出解决方案。"},{key:"C",label:"先定义概念，再提供例证。"},{key:"D",label:"先比较两国，再得出政策建议。"}],correctOptionKey:"A",explanation:"前半句承认出口回升，however 后指出回升过窄，不能保证持久复苏。"},{id:"logic-condition-1",sectionId:"logic-relations",categoryKey:"condition-hypothesis",categoryLabel:"条件假设",prompt:"If 从句在这句话中的作用是什么？",sourceSentence:"If energy prices rise again this winter, the central bank may have to delay any discussion of cuts.",options:[{key:"A",label:"补充已经发生的背景事实。"},{key:"B",label:"设置条件，限定主句判断成立的前提。"},{key:"C",label:"对主句中的名词作同位解释。"},{key:"D",label:"表示主句动作发生的时间。"}],correctOptionKey:"B",explanation:"If 从句提出一个可能成立的条件，主句是在该条件下的政策推断。"},{id:"logic-condition-2",sectionId:"logic-relations",categoryKey:"condition-hypothesis",categoryLabel:"条件假设",prompt:"Provided that 这个结构在句子里表达什么？",sourceSentence:"Provided that productivity keeps improving, the firm can absorb higher wages without raising prices too sharply.",options:[{key:"A",label:"转折让步：尽管生产率上升。"},{key:"B",label:"时间先后：当生产率上升之后。"},{key:"C",label:"条件限定：只有在生产率持续改善时。"},{key:"D",label:"因果解释：因为生产率已经改善。"}],correctOptionKey:"C",explanation:"Provided that 等于 only if，表达强条件限制。"},{id:"logic-condition-3",sectionId:"logic-relations",categoryKey:"condition-hypothesis",categoryLabel:"条件假设",prompt:"Without 短语在句中更接近哪类逻辑？",sourceSentence:"Without a credible plan to cut debt, investors are unlikely to believe the government’s growth story.",options:[{key:"A",label:"隐含条件：如果没有某前提，主句结果难以成立。"},{key:"B",label:"并列说明：补充另一个积极事实。"},{key:"C",label:"举例说明：给出一个债务案例。"},{key:"D",label:"递进推进：把前一句进一步展开。"}],correctOptionKey:"A",explanation:"Without 短语相当于一个否定条件，说明在缺乏可信减债方案的情况下，投资者不会相信政府叙事。"},{id:"logic-progress-1",sectionId:"logic-relations",categoryKey:"progression-example",categoryLabel:"递进举例",prompt:"For example 在句中的作用是？",sourceSentence:"Many firms are rethinking office space. For example, several banks now expect staff to share desks on alternating days.",options:[{key:"A",label:"通过具体案例支撑前面的总体判断。"},{key:"B",label:"纠正前一句中的错误结论。"},{key:"C",label:"把抽象观点转成条件句。"},{key:"D",label:"说明前一句和后一句没有关系。"}],correctOptionKey:"A",explanation:"第二句用 several banks 的做法作为例子，支撑 many firms are rethinking office space 这一概括判断。"},{id:"logic-progress-2",sectionId:"logic-relations",categoryKey:"progression-example",categoryLabel:"递进举例",prompt:"Indeed 在这里最合适的理解是什么？",sourceSentence:"The labour market is cooling. Indeed, hiring plans in manufacturing have weakened for three straight quarters.",options:[{key:"A",label:"引出一个更具体、更能证明前句的强化信息。"},{key:"B",label:"引出与前句对立的修正意见。"},{key:"C",label:"表明前句只是作者的假设。"},{key:"D",label:"表示主句发生的地点。"}],correctOptionKey:"A",explanation:"Indeed 常用于强调或强化前句，这里用制造业招聘计划连续疲弱来增强前句判断。"},{id:"logic-progress-3",sectionId:"logic-relations",categoryKey:"progression-example",categoryLabel:"递进举例",prompt:"Not only ... but also ... 在这句话中体现的是什么推进关系？",sourceSentence:"The policy not only lowered borrowing costs but also signalled that officials were willing to act quickly.",options:[{key:"A",label:"先举例后总结。"},{key:"B",label:"从一个效果推进到更深一层的附加效果。"},{key:"C",label:"把两个互斥结果并列比较。"},{key:"D",label:"先让步后转折。"}],correctOptionKey:"B",explanation:"not only ... but also ... 强调递进：除了降低借贷成本，还释放了政策信号。"},{id:"analysis-main-1",sectionId:"sentence-analysis",categoryKey:"main-clause",categoryLabel:"主干识别",prompt:"这句话的主句核心主干是哪一项？",sourceSentence:"Despite months of political noise, investors still expect the reform package to pass.",options:[{key:"A",label:"Despite months of political noise"},{key:"B",label:"investors still expect"},{key:"C",label:"the reform package to pass"},{key:"D",label:"months of political noise"}],correctOptionKey:"B",explanation:"句子的真正主干是 investors expect，despite 短语只是让步状语，to pass 是宾补结构的一部分。"},{id:"analysis-main-2",sectionId:"sentence-analysis",categoryKey:"main-clause",categoryLabel:"主干识别",prompt:"句子的核心谓语中心应识别为哪一项？",sourceSentence:"After years of underinvestment, the rail network is finally beginning to recover.",options:[{key:"A",label:"After years of underinvestment"},{key:"B",label:"the rail network"},{key:"C",label:"is beginning"},{key:"D",label:"to recover"}],correctOptionKey:"C",explanation:"主语是 the rail network，谓语中心是 is beginning，to recover 为不定式补足 beginning 的内容。"},{id:"analysis-main-3",sectionId:"sentence-analysis",categoryKey:"main-clause",categoryLabel:"主干识别",prompt:"哪一项是整句作者真正陈述的主干？",sourceSentence:"What worries bond markets most is the absence of a credible fiscal anchor.",options:[{key:"A",label:"What worries bond markets most"},{key:"B",label:"bond markets most is"},{key:"C",label:"is the absence"},{key:"D",label:"a credible fiscal anchor"}],correctOptionKey:"C",explanation:"整句是主语从句 + 系表结构，作者真正断言的核心骨架是 “X is the absence ...”。"},{id:"analysis-clause-1",sectionId:"sentence-analysis",categoryKey:"clause-function",categoryLabel:"从句功能",prompt:"that the slowdown is temporary 在句中充当什么成分？",sourceSentence:"Analysts argue that the slowdown is temporary.",options:[{key:"A",label:"主语从句"},{key:"B",label:"宾语从句"},{key:"C",label:"定语从句"},{key:"D",label:"状语从句"}],correctOptionKey:"B",explanation:"that 从句作 argue 的宾语，说明分析师主张的内容。"},{id:"analysis-clause-2",sectionId:"sentence-analysis",categoryKey:"clause-function",categoryLabel:"从句功能",prompt:"that remains after the merger 在句中属于哪类从句？",sourceSentence:"The unit that remains after the merger will focus on software.",options:[{key:"A",label:"宾语从句"},{key:"B",label:"表语从句"},{key:"C",label:"限制性定语从句"},{key:"D",label:"结果状语从句"}],correctOptionKey:"C",explanation:"that remains after the merger 修饰 the unit，限定是哪一个 unit，因此是限制性定语从句。"},{id:"analysis-clause-3",sectionId:"sentence-analysis",categoryKey:"clause-function",categoryLabel:"从句功能",prompt:"When demand weakens further 在整句中的功能是？",sourceSentence:"When demand weakens further, producers may finally cut output.",options:[{key:"A",label:"时间/条件状语从句，交代主句判断成立的场景。"},{key:"B",label:"同位语从句，解释 demand 的内容。"},{key:"C",label:"宾语从句，作 cut 的宾语。"},{key:"D",label:"定语从句，修饰 producers。"}],correctOptionKey:"A",explanation:"When 从句在此提供时间兼条件场景，主句是该场景下可能出现的动作。"},{id:"analysis-nonfinite-1",sectionId:"sentence-analysis",categoryKey:"non-finite-compression",categoryLabel:"非谓语压缩",prompt:"Having failed to raise fresh capital, the company entered talks with creditors. 句首分词结构压缩了什么关系？",sourceSentence:"Having failed to raise fresh capital, the company entered talks with creditors.",options:[{key:"A",label:"压缩了一个先于主句发生的原因背景。"},{key:"B",label:"压缩了一个与主句并列的主谓结构。"},{key:"C",label:"压缩了一个修饰 creditors 的定语从句。"},{key:"D",label:"压缩了一个表示让步的 although 从句。"}],correctOptionKey:"A",explanation:"Having failed 强调先发生的失败背景，并构成主句 entered talks 的原因前提。"},{id:"analysis-nonfinite-2",sectionId:"sentence-analysis",categoryKey:"non-finite-compression",categoryLabel:"非谓语压缩",prompt:"The minister, hoping to calm markets, promised a clearer timetable. 中间插入的 hoping to ... 更接近什么？",sourceSentence:"The minister, hoping to calm markets, promised a clearer timetable.",options:[{key:"A",label:"补充主语意图的分词状语。"},{key:"B",label:"替代 promised 的真正谓语。"},{key:"C",label:"修饰 timetable 的后置定语。"},{key:"D",label:"说明 markets 的被动状态。"}],correctOptionKey:"A",explanation:"hoping to calm markets 是现在分词状语，补充 minister 作出 promise 时的目的/意图。"},{id:"analysis-nonfinite-3",sectionId:"sentence-analysis",categoryKey:"non-finite-compression",categoryLabel:"非谓语压缩",prompt:"Measures announced late on Friday failed to reassure traders. announced late on Friday 的作用是？",sourceSentence:"Measures announced late on Friday failed to reassure traders.",options:[{key:"A",label:"过去分词短语，压缩了修饰 measures 的定语从句。"},{key:"B",label:"主句谓语的一部分。"},{key:"C",label:"表示结果的状语结构。"},{key:"D",label:"独立主格结构。"}],correctOptionKey:"A",explanation:"announced late on Friday 相当于 which were announced late on Friday，修饰 Measures。"},{id:"analysis-modifier-1",sectionId:"sentence-analysis",categoryKey:"modifier-attachment",categoryLabel:"修饰语指向",prompt:"in several export markets 这个介词短语最直接修饰哪一部分？",sourceSentence:"The company reported weaker demand in several export markets.",options:[{key:"A",label:"reported"},{key:"B",label:"weaker demand"},{key:"C",label:"the company"},{key:"D",label:"several"}],correctOptionKey:"B",explanation:"该介词短语限定的是 demand 发生的范围，即在若干出口市场中的需求。"},{id:"analysis-modifier-2",sectionId:"sentence-analysis",categoryKey:"modifier-attachment",categoryLabel:"修饰语指向",prompt:"facing rising defaults 这一分词短语更合理地修饰谁？",sourceSentence:"Banks facing rising defaults have tightened lending standards.",options:[{key:"A",label:"Banks"},{key:"B",label:"defaults"},{key:"C",label:"lending standards"},{key:"D",label:"have tightened"}],correctOptionKey:"A",explanation:"现在分词短语作后置定语，修饰主语 Banks，说明是哪一类银行。"},{id:"analysis-modifier-3",sectionId:"sentence-analysis",categoryKey:"modifier-attachment",categoryLabel:"修饰语指向",prompt:"which startled investors 中的 which 最自然回指什么？",sourceSentence:"The firm delayed the listing, which startled investors.",options:[{key:"A",label:"the firm"},{key:"B",label:"the listing"},{key:"C",label:"前面整件“推迟上市”这件事"},{key:"D",label:"investors"}],correctOptionKey:"C",explanation:"非限制性 which 常可回指前面整件事，这里回指的是公司推迟上市这一动作，而非单独的 listing。"}])}}});